# -*- coding: utf-8 -*-
"""
DiffuSVG_Dataset_Finetune.py
Usage on Colab: !python DiffuSVG_Dataset_Finetune.py
Set HF_TOKEN at the top.
"""

# ═══════════════════════════════════════════════════════════════════════════
#  DiffuSVG — Full Pipeline (whiteboard)
#  Text Prompt → SD3.5-M → image → Potrace+ImageMagick → SVG
#                        → Qwen2VL Y/X gate → dataset → LoRA fine-tune
# ═══════════════════════════════════════════════════════════════════════════

# ── CONFIG — fill in tokens before running ────────────────────────────────
HF_TOKEN        = "YOUR_HF_TOKEN_HERE"  # huggingface.co/settings/tokens
RESULTS_JSON    = "results.json"
OUTPUT_DIR      = "./dataset"
LORA_OUTPUT_DIR = "./qwen2vl_svg_lora"
CLIP_THRESHOLD  = 24.0
DINO_THRESHOLD  = 0.35
SD_STEPS        = 30
SD_GUIDANCE     = 5.0
SD_SEED         = 42
USE_VLM_FILTER  = True          # Qwen2VL Y/X gate as shown in whiteboard
VLM_MODEL       = "Qwen/Qwen2-VL-2B-Instruct"
EPOCHS          = 3
FORCE_REGEN     = True          # Clear existing dataset and re-run
BATCH_SIZE      = 1
GRAD_ACCUM      = 8   # higher = handles longer sequences (1024 tok) without OOM
LEARNING_RATE   = 2e-4
LORA_R          = 4
LORA_ALPHA      = 16
LORA_DROPOUT    = 0.15
assert HF_TOKEN, "Set HF_TOKEN above"

# ── STEP 0: Install ───────────────────────────────────────────────────────
import subprocess, shutil, sys, os, gc, json, logging, base64, io
from pathlib import Path

# Reduce CUDA memory fragmentation
os.environ["PYTORCH_ALLOC_CONF"] = "expandable_segments:True"

def _run(cmd):
    r = subprocess.run(cmd, capture_output=True, text=True)
    if r.returncode != 0: print(f"WARN: {r.stderr.strip()[-200:]}")
    return r.returncode == 0

print("apt-get update ...")
_run(["apt-get", "update", "-q"])
for pkg in ["potrace", "imagemagick"]:
    print(f"Installing {pkg} ...")
    _run(["apt-get", "install", "-y", "--fix-missing", "--no-install-recommends", pkg])

missing = [t for t in ["potrace", "convert"] if not shutil.which(t)]
if missing:
    raise EnvironmentError(f"Tools not found: {missing}. Try: Runtime -> Disconnect and delete runtime.")

print("potrace :", subprocess.run(["potrace","--version"], capture_output=True, text=True).stdout.split("\n")[0])
print("convert :", subprocess.run(["convert","--version"],  capture_output=True, text=True).stdout.split("\n")[0])
print("pip install ...")
subprocess.run([sys.executable, "-m", "pip", "install", "-q",
    "diffusers", "transformers", "accelerate", "bitsandbytes",
    "peft", "trl", "cairosvg", "pillow", "tqdm", "sentencepiece", "requests"], check=True)

# ── STEP 1: Write helper files ────────────────────────────────────────────
_VEC_B64 = ""
_DS_B64  = ""

for _fname, _b64 in [("vectorize.py", _VEC_B64), ("dataset_pipeline.py", _DS_B64)]:
    with open(_fname, "w", encoding="utf-8") as _f:
        _f.write(base64.b64decode(_b64).decode("utf-8"))
    print(f"Written: {_fname}")
del _VEC_B64, _DS_B64  # free large strings from RAM

# ── STEP 2: GPU check ─────────────────────────────────────────────────────
import torch
if not torch.cuda.is_available():
    raise RuntimeError("No GPU. Runtime -> Change runtime type -> T4 GPU")
print(f"GPU: {torch.cuda.get_device_name(0)}  ({torch.cuda.get_device_properties(0).total_memory/1e9:.1f} GB)")
os.environ["HF_TOKEN"] = HF_TOKEN

# ── STEP 3: Upload results.json ───────────────────────────────────────────
if not Path(RESULTS_JSON).exists():
    print("Upload results.json ...")
    from google.colab import files as _colab_files
    uploaded = _colab_files.upload()
    for name in uploaded:
        Path(name).rename(RESULTS_JSON)
    print(f"Saved: {RESULTS_JSON}")
else:
    print(f"Found: {RESULTS_JSON}")

# ── GPU sanity check + auto-cleanup ──────────────────────────────────────
_free_gb = (torch.cuda.get_device_properties(0).total_memory - torch.cuda.memory_reserved(0)) / 1e9
if _free_gb < 4.0:
    print(f"GPU only {_free_gb:.1f} GB free — attempting auto-cleanup of stale models ...")
    for _stale in ["ft_model", "trainer", "pipeline", "generate_image", "qwen_model", "qwen_processor"]:
        try:
            del globals()[_stale]
            print(f"  deleted {_stale}")
        except KeyError:
            pass
    gc.collect()
    torch.cuda.empty_cache()
    torch.cuda.synchronize()
    _free_gb = (torch.cuda.get_device_properties(0).total_memory - torch.cuda.memory_reserved(0)) / 1e9
    print(f"  GPU free after cleanup: {_free_gb:.1f} GB")
    if _free_gb < 4.0:
        raise RuntimeError(
            f"Still only {_free_gb:.1f} GB GPU free after cleanup.\n"
            "Fix: Runtime → Disconnect and delete runtime → Reconnect, then re-run."
        )
print(f"GPU free: {_free_gb:.1f} GB  ✓")

# ── Skip-generation flag ─────────────────────────────────────────────────
_train_jsonl = Path(OUTPUT_DIR) / "dataset_train.jsonl"

# FORCE_REGEN: wipe existing dataset so pipeline re-runs with fresh SVGs
if FORCE_REGEN and _train_jsonl.exists():
    import shutil as _shutil
    _shutil.rmtree(OUTPUT_DIR, ignore_errors=True)
    Path(OUTPUT_DIR).mkdir(parents=True, exist_ok=True)
    print("FORCE_REGEN: cleared dataset — will regenerate.")

_SKIP_GENERATION = (not FORCE_REGEN) and _train_jsonl.exists() and _train_jsonl.stat().st_size > 100
if _SKIP_GENERATION:
    print()
    print(f"Found existing dataset: {_train_jsonl}  ({_train_jsonl.stat().st_size:,} bytes)")
    print("Skipping generation (set FORCE_REGEN=True to rebuild).")
    jsonl_path = Path(OUTPUT_DIR) / "dataset.jsonl"
    train_path = _train_jsonl
    val_path = None
else:  # run the full pipeline

    # ── STEP 4: Mine bad prompts ──────────────────────────────────────────
    from dataset_pipeline import mine_bad_prompts

    bad_prompts, breakdown = mine_bad_prompts(RESULTS_JSON, CLIP_THRESHOLD, DINO_THRESHOLD)
    print(f"Bad prompts: {breakdown['bad_total']}/{breakdown['total']}  "
          f"(failures={breakdown['failed']}, low_clip={breakdown['low_clip']}, low_dino={breakdown['low_dino']})")
    for i, p in enumerate(bad_prompts, 1): print(f"  {i:2d}. {p}")

    logging.basicConfig(level=logging.INFO, format="%(asctime)s [%(levelname)s] %(message)s", force=True)

    # ── STEP 5 + 6: Pass 1 — SD3.5-M (no T5) + Potrace → SVG candidates ──
    # KEY: Load ONLY SD3.5-M now. Qwen2VL loads AFTER SD3.5-M is deleted.
    # Reason: bitsandbytes 4-bit silently falls back to fp32 on CPU → Qwen2VL-2B
    # consumes ~8 GB system RAM. SD3.5-M (no T5) = ~5.8 GB. Together they exceed
    # Colab's ~12 GB system RAM limit and crash. Sequential loading avoids this.
    from diffusers import StableDiffusion3Pipeline
    from vectorize import Vectorizer, is_good_svg

    Path(OUTPUT_DIR).mkdir(parents=True, exist_ok=True)
    (Path(OUTPUT_DIR) / "images").mkdir(exist_ok=True)

    print("Loading SD3.5-M (no T5-XXL, saves ~9.4 GB system RAM) ...")
    _sd_pipe = StableDiffusion3Pipeline.from_pretrained(
        "stabilityai/stable-diffusion-3.5-medium",
        text_encoder_3=None,   # drop T5-XXL → saves ~9.4 GB system RAM
        tokenizer_3=None,
        torch_dtype=torch.float16,
        token=HF_TOKEN,
    )
    _sd_pipe.enable_model_cpu_offload()

    _ICON_STYLE = (
        "ultra-simple flat vector icon, geometric shapes only, solid colors, "
        "no gradients, no shadows, no texture, minimalist, SVG-ready, "
    )

    @torch.inference_mode()
    def _sd_gen(prompt, seed=None):
        gen = torch.Generator("cuda").manual_seed(seed) if seed is not None else None
        return _sd_pipe(
            _ICON_STYLE + prompt,
            negative_prompt="gradient, shadow, texture, 3d, realistic, photograph, complex details, blurry",
            num_inference_steps=SD_STEPS, guidance_scale=SD_GUIDANCE, generator=gen,
        ).images[0]

    _vec = Vectorizer(threshold=0.45, resolution=512)
    _candidates = []  # (prompt, svg) pairs that pass structural check

    print(f"\nPass 1: SD3.5-M + Potrace for {len(bad_prompts)} prompts ...")
    for _i, _p in enumerate(bad_prompts):
        try:
            _img = _sd_gen(_p, seed=(SD_SEED + _i) if SD_SEED is not None else None)
            _img.save(Path(OUTPUT_DIR) / "images" / f"{_i:05d}.png")
            _svg = _vec.vectorize(_img, prompt=_p)
            if _svg and is_good_svg(_svg, 1, 500):
                _candidates.append((_p, _svg))
                print(f"  [{_i+1}/{len(bad_prompts)}] OK   {_p[:60]}")
            else:
                print(f"  [{_i+1}/{len(bad_prompts)}] SKIP bad-svg-structure  {_p[:60]}")
        except Exception as _e:
            print(f"  [{_i+1}/{len(bad_prompts)}] ERR  {_e}")

    print(f"\nPass 1 done: {len(_candidates)}/{len(bad_prompts)} structural-pass candidates")

    # Free SD3.5-M from system RAM BEFORE loading Qwen2VL
    del _sd_pipe, _sd_gen
    gc.collect(); torch.cuda.empty_cache()
    print(f"SD3.5-M freed.  GPU alloc: {torch.cuda.memory_allocated(0)/1e9:.2f} GB")

    # ── STEP 7: Pass 2 — Qwen2VL Y/X gate (GPU 4-bit, no SD3.5-M in RAM) ──
    if USE_VLM_FILTER and _candidates:
        from dataset_pipeline import VLMQualityFilter
        print(f"\nPass 2: Loading Qwen2VL ({VLM_MODEL}) on GPU (4-bit) ...")
        _vlm = VLMQualityFilter(model_name=VLM_MODEL, load_in_4bit=True, device="cuda")
        _final = []
        for _p, _svg in _candidates:
            if _vlm.is_good(_svg, _p):
                _final.append((_p, _svg)); print(f"  Y: {_p[:70]}")
            else:
                print(f"  X: {_p[:70]}")
        del _vlm; gc.collect(); torch.cuda.empty_cache()
        print(f"Pass 2 done: {len(_final)}/{len(_candidates)} accepted by VLM gate")
    else:
        _final = _candidates
        if not USE_VLM_FILTER:
            print("VLM gate skipped (USE_VLM_FILTER=False).")

    # Write JSONL dataset
    jsonl_path = Path(OUTPUT_DIR) / "dataset.jsonl"
    with open(jsonl_path, "w", encoding="utf-8") as _jf:
        for _p, _svg in _final:
            _jf.write(json.dumps({"text": _p, "svg": _svg}, ensure_ascii=False) + "\n")
    print(f"\nDataset written: {jsonl_path}  ({len(_final)} records)")
    # ── STEP 8: Show samples ───────────────────────────────────────────────
    try:
        from IPython.display import SVG as _SVG_display, display as _display
        print(f"\nDataset records: {len(_final)}")
        for _p, _svg in _final[:3]:
            print(f"Prompt: {_p}")
            _display(_SVG_display(_svg))
    except Exception:
        pass

    # ── STEP 9: Split dataset ─────────────────────────────────────────────
    import random as _random
    _random.seed(42); _random.shuffle(_final)
    _split = max(1, int(len(_final) * 0.9))
    _tr, _vl = _final[:_split], _final[_split:]
    train_path = Path(OUTPUT_DIR) / "dataset_train.jsonl"
    val_path   = Path(OUTPUT_DIR) / "dataset_val.jsonl" if _vl else None
    with open(train_path, "w", encoding="utf-8") as _f:
        for _p, _svg in _tr: _f.write(json.dumps({"text": _p, "svg": _svg}, ensure_ascii=False) + "\n")
    if val_path:
        with open(val_path, "w", encoding="utf-8") as _f:
            for _p, _svg in _vl: _f.write(json.dumps({"text": _p, "svg": _svg}, ensure_ascii=False) + "\n")
    print(f"Train: {train_path} ({len(_tr)})  Val: {val_path} ({len(_vl)})")

# ── STEP 10: Final GPU cleanup before fine-tuning ─────────────────────────
# SD3.5-M and Qwen2VL (VLM gate) were already deleted in Steps 6+7.
# Just flush any lingering cache before loading the fine-tune model.
print("\nFlushing GPU cache before fine-tuning ...")
gc.collect()
torch.cuda.empty_cache()
print(f"VRAM free: {torch.cuda.memory_reserved(0)/1e9:.2f} GB reserved, "
      f"{torch.cuda.memory_allocated(0)/1e9:.2f} GB allocated")

# ── STEP 11: Fine-tune (fully inline) ────────────────────────────────────
from transformers import AutoTokenizer, EarlyStoppingCallback, TrainingArguments, Trainer, Qwen2VLForConditionalGeneration, BitsAndBytesConfig
from peft import LoraConfig, get_peft_model, TaskType, prepare_model_for_kbit_training

SYSTEM_PROMPT = (
    "You are an expert SVG code generator. "
    "Given a text description, output ONLY valid SVG code. "
    "Rules:\n"
    '- Start with: <svg viewBox="0 0 200 200" xmlns="http://www.w3.org/2000/svg">\n'
    '- Use simple shapes: <rect>, <circle>, <ellipse>, <polygon>, <path>\n'
    '- Use solid hex fill colours (e.g., fill="#FF0000")\n'
    "- Keep it minimal: 5-20 elements\n- End with: </svg>\n"
    "Output the SVG code directly, no explanation."
)

def _build_chat(prompt, svg, tok):
    return tok.apply_chat_template([
        {"role":"system",    "content":SYSTEM_PROMPT},
        {"role":"user",      "content":f"Generate SVG for: {prompt}"},
        {"role":"assistant", "content":svg},
    ], tokenize=False, add_generation_prompt=False)

class _SVGDataset(torch.utils.data.Dataset):
    def __init__(self, recs, tok, ml=1024): self.recs, self.tok, self.ml = recs, tok, ml
    def __len__(self): return len(self.recs)
    def __getitem__(self, idx):
        r = self.recs[idx]
        enc = self.tok(_build_chat(r["text"], r["svg"], self.tok),
                       truncation=True, max_length=self.ml, padding=False, return_tensors=None)
        ids = enc["input_ids"]; labs = list(ids)
        asst = self.tok.encode("<|im_start|>assistant", add_special_tokens=False)
        n, end = len(asst), 0
        for i in range(len(ids)-n):
            if ids[i:i+n] == asst: end = i+n
        for i in range(end): labs[i] = -100
        return {"input_ids":ids, "labels":labs, "attention_mask":enc["attention_mask"]}

class _Collator:
    def __init__(self, tok, ml=1024): self.tok, self.ml = tok, ml
    def __call__(self, fs):
        ml = min(max(len(f["input_ids"]) for f in fs), self.ml); pad = self.tok.pad_token_id or 0
        return {
            "input_ids":      torch.tensor([(f["input_ids"]     +[pad] *(ml-len(f["input_ids"])))[:ml] for f in fs], dtype=torch.long),
            "labels":         torch.tensor([(f["labels"]        +[-100]*(ml-len(f["labels"])))[:ml]    for f in fs], dtype=torch.long),
            "attention_mask": torch.tensor([(f["attention_mask"]+[0]   *(ml-len(f["attention_mask"])))[:ml] for f in fs], dtype=torch.long),
        }

_train_recs = [json.loads(l) for l in open(str(train_path), encoding="utf-8") if l.strip()]
if not _train_recs:
    print("WARNING: dataset is empty — all diffusion steps failed. Cannot fine-tune.")
    print("This usually means Qwen2VL was not properly offloaded to CPU before SD generation.")
    print("Re-run after a Runtime -> Disconnect and delete runtime -> reconnect.")
else:
    _val_recs = [json.loads(l) for l in open(str(val_path), encoding="utf-8") if l.strip()] if val_path and Path(str(val_path)).exists() else []
    print(f"\nLoading model for fine-tuning ... Train: {len(_train_recs)}  Val: {len(_val_recs)}")

    tokenizer = AutoTokenizer.from_pretrained(VLM_MODEL, trust_remote_code=True, padding_side="right")
    if tokenizer.pad_token is None: tokenizer.pad_token = tokenizer.eos_token

    quant = BitsAndBytesConfig(load_in_4bit=True, bnb_4bit_compute_dtype=torch.float16,
                                bnb_4bit_quant_type="nf4", bnb_4bit_use_double_quant=True)
    ft_model = Qwen2VLForConditionalGeneration.from_pretrained(
        VLM_MODEL, quantization_config=quant, device_map={"":0},
        trust_remote_code=True, low_cpu_mem_usage=True)
    ft_model = prepare_model_for_kbit_training(ft_model, use_gradient_checkpointing=True)
    ft_model = get_peft_model(ft_model, LoraConfig(
        task_type=TaskType.CAUSAL_LM, r=LORA_R, lora_alpha=LORA_ALPHA, lora_dropout=LORA_DROPOUT,
        target_modules=["q_proj","k_proj","v_proj","o_proj","gate_proj","up_proj","down_proj"], bias="none"))
    ft_model.print_trainable_parameters()

    trainer = Trainer(
        model=ft_model, processing_class=tokenizer,
        data_collator=_Collator(tokenizer),
        train_dataset=_SVGDataset(_train_recs, tokenizer),
        eval_dataset =_SVGDataset(_val_recs,   tokenizer) if _val_recs else None,
        args=TrainingArguments(
            output_dir=LORA_OUTPUT_DIR, num_train_epochs=EPOCHS,
            per_device_train_batch_size=BATCH_SIZE, gradient_accumulation_steps=GRAD_ACCUM,
            learning_rate=LEARNING_RATE, lr_scheduler_type="cosine", warmup_ratio=0.05,
            fp16=True, logging_steps=10,
            gradient_checkpointing=True,
            optim="paged_adamw_8bit",
            eval_strategy="steps" if _val_recs else "no", eval_steps=100 if _val_recs else None,
            save_strategy="steps", save_steps=200, save_total_limit=3,
            load_best_model_at_end=bool(_val_recs),
            metric_for_best_model="eval_loss" if _val_recs else None,
            report_to="none", seed=42, remove_unused_columns=False,
            dataloader_pin_memory=False, dataloader_num_workers=0,
        ),
        callbacks=[EarlyStoppingCallback(early_stopping_patience=1)] if _val_recs else None,
    )
    print("Training ..."); trainer.train()

    adapter_path = os.path.join(LORA_OUTPUT_DIR, "final_adapter")
    ft_model.save_pretrained(adapter_path); tokenizer.save_pretrained(adapter_path)
    print(f"\nAdapter saved: {adapter_path}")

    import shutil as _shutil
    from google.colab import files as _colab_files
    zip_path = _shutil.make_archive("qwen2vl_svg_lora", "zip", adapter_path)
    _colab_files.download(zip_path)
    print("Done!")
